{
  "executive_summary": "Zero-downtime migration of Order Management from MongoDB to PostgreSQL using a Change Data Capture (CDC) pipeline with a Strangler Fig cutover strategy. The architecture avoids application-level dual-writes (which introduce distributed transaction risks) in favor of MongoDB Change Streams feeding a sync worker that writes to PostgreSQL. Migration proceeds in four phases: Schema Deploy → CDC Sync + Backfill → Shadow Verification → Read Cutover → MongoDB Decommission. At 200 writes/min, the CDC lag will be sub-second, making this approach safe and reversible at every stage.",

  "architecture": {
    "components": [
      {
        "name": "Order Service (existing)",
        "responsibility": "Handles all order CRUD. During migration, continues writing to MongoDB as primary. After cutover, writes directly to PostgreSQL.",
        "boundaries": "Owns order lifecycle. Reads are switched via feature flag (read-source: mongo | postgres | shadow-both)."
      },
      {
        "name": "CDC Sync Worker",
        "responsibility": "Consumes MongoDB Change Streams for the orders and payments collections. Transforms BSON documents into relational rows and writes to PostgreSQL. Tracks resume tokens for crash recovery.",
        "boundaries": "Stateless except for resume token persistence. Does NOT serve production reads. Isolated deployment unit."
      },
      {
        "name": "Backfill Job",
        "responsibility": "One-time bulk migration of 8M historical documents from MongoDB to PostgreSQL using cursor-based pagination. Runs concurrently with CDC without conflict due to idempotent upserts keyed on order_id.",
        "boundaries": "Batch process. Throttled to avoid impacting production MongoDB. Writes use ON CONFLICT DO UPDATE to merge safely with CDC stream."
      },
      {
        "name": "Reconciliation Service",
        "responsibility": "Periodically samples records from both stores, compares field-by-field, and reports drift. Produces a reconciliation report with match rate. Migration cannot proceed to cutover until match rate is 100% for 72 hours.",
        "boundaries": "Read-only against both databases. Outputs metrics and alerts only."
      },
      {
        "name": "Shadow Read Proxy",
        "responsibility": "When feature flag is set to shadow-both, issues reads to both MongoDB and PostgreSQL in parallel. Returns MongoDB result to caller but logs any divergence from PostgreSQL result. Validates read correctness before cutover.",
        "boundaries": "Sits inside Order Service as a middleware layer, not a separate deployment. Adds ~5ms latency during shadow phase only."
      },
      {
        "name": "PostgreSQL (target)",
        "responsibility": "Relational store for orders, order_items, payments, and payment_events. Enforces FK constraints, supports ACID transactions across order+payment, enables complex reporting joins.",
        "boundaries": "Initially write-only target of CDC. Becomes primary after cutover. Sized for 8M orders with growth headroom."
      },
      {
        "name": "Feature Flag Controller",
        "responsibility": "Controls read-source and write-target switches. Supports gradual rollout (e.g., 1% → 10% → 50% → 100% of reads from PostgreSQL). Enables instant rollback by flipping flag.",
        "boundaries": "External to Order Service. Can be existing feature flag system (LaunchDarkly, Unleash, env-based)."
      }
    ],
    "interfaces": [
      {
        "from": "MongoDB",
        "to": "CDC Sync Worker",
        "contract": "MongoDB Change Stream (resume token-based). Events: insert, update, replace, delete on orders and payments collections.",
        "coupling_type": "event-driven (loose)"
      },
      {
        "from": "CDC Sync Worker",
        "to": "PostgreSQL",
        "contract": "Idempotent upserts via ON CONFLICT (order_id) DO UPDATE. Transforms: embedded arrays → child tables, ObjectId → UUID, nested payment → normalized payment rows.",
        "coupling_type": "data (moderate, schema-aware)"
      },
      {
        "from": "Backfill Job",
        "to": "MongoDB",
        "contract": "Read-only cursor with batch_size=1000, sorted by _id. Uses read preference secondaryPreferred to avoid primary load.",
        "coupling_type": "data (read-only)"
      },
      {
        "from": "Backfill Job",
        "to": "PostgreSQL",
        "contract": "Batch INSERT ... ON CONFLICT DO UPDATE. Same transform logic as CDC worker (shared library).",
        "coupling_type": "data (write)"
      },
      {
        "from": "Order Service",
        "to": "Feature Flag Controller",
        "contract": "getFlag('order-read-source') → 'mongo' | 'postgres' | 'shadow'. getFlag('order-write-target') → 'mongo' | 'postgres' | 'both'.",
        "coupling_type": "configuration (loose)"
      },
      {
        "from": "Reconciliation Service",
        "to": "MongoDB + PostgreSQL",
        "contract": "Read-only sampling: SELECT by order_id from PostgreSQL, findOne by _id from MongoDB. Field-level comparison with tolerance for timestamp precision differences.",
        "coupling_type": "data (read-only)"
      }
    ],
    "data_flow": "Phase 1-2: All writes → MongoDB → Change Stream → CDC Worker → PostgreSQL. Backfill Job reads historical MongoDB docs → PostgreSQL (idempotent, merges with CDC). Phase 3: Reads go to both (shadow mode), MongoDB result returned, divergence logged. Phase 4: Feature flag switches reads to PostgreSQL. Write flag switches to 'both' (application dual-write) briefly, then to 'postgres-only'. Phase 5: CDC and MongoDB decommissioned.",
    "patterns_used": [
      {
        "pattern": "Strangler Fig",
        "rationale": "Incrementally migrates reads and writes from MongoDB to PostgreSQL without big-bang cutover. Each phase is independently reversible."
      },
      {
        "pattern": "Change Data Capture (CDC)",
        "rationale": "Avoids application-level dual-write during the bulk of migration. MongoDB Change Streams provide at-least-once delivery with resume tokens. Idempotent upserts on the PostgreSQL side make this safe."
      },
      {
        "pattern": "Shadow Reads",
        "rationale": "Validates PostgreSQL correctness under real production query patterns before cutover. Catches transform bugs, missing data, and query semantic differences."
      },
      {
        "pattern": "Idempotent Write (Upsert)",
        "rationale": "Allows CDC and Backfill to run concurrently without coordination. Both use ON CONFLICT DO UPDATE keyed on order_id, so duplicate or out-of-order writes converge to correct state."
      },
      {
        "pattern": "Feature Flag Rollout",
        "rationale": "Enables percentage-based cutover with instant rollback. Decouples deployment from activation."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Order Management",
        "classification": "core",
        "aggregates": [
          {
            "name": "Order",
            "root": "Order",
            "entities": ["Order", "OrderItem"],
            "value_objects": ["Money", "ShippingAddress", "OrderStatus"],
            "invariants": [
              "Order total must equal sum of item subtotals",
              "Order cannot transition to shipped without payment confirmation",
              "OrderItems cannot be modified after order is confirmed"
            ],
            "pg_tables": ["orders", "order_items"]
          },
          {
            "name": "Payment",
            "root": "Payment",
            "entities": ["Payment", "PaymentEvent"],
            "value_objects": ["Money", "PaymentMethod", "PaymentStatus"],
            "invariants": [
              "Payment amount must match order total",
              "Refund cannot exceed original payment amount",
              "Payment events are append-only"
            ],
            "pg_tables": ["payments", "payment_events"]
          }
        ]
      },
      {
        "name": "Migration Infrastructure",
        "classification": "generic",
        "aggregates": [
          {
            "name": "SyncState",
            "root": "SyncCursor",
            "entities": ["SyncCursor", "ReconciliationReport"],
            "value_objects": ["ResumeToken", "MigrationPhase"],
            "invariants": ["Resume token must advance monotonically"],
            "pg_tables": ["migration_sync_state", "reconciliation_reports"]
          }
        ]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management (MongoDB - legacy)",
        "downstream": "CDC Sync Worker",
        "relationship": "Published Language — Change Stream events are the published contract. CDC Worker implements an Anti-Corruption Layer to translate document model to relational model."
      },
      {
        "upstream": "Order Management (PostgreSQL - target)",
        "downstream": "Reporting / Analytics",
        "relationship": "Open Host Service — PostgreSQL enables direct SQL access for reporting, which was the primary driver for migration."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "CDC via Change Streams instead of application-level dual-write",
      "gains": "No distributed transaction risk. No changes to write path during migration. CDC is decoupled and independently deployable. Resume tokens provide exactly-once semantics with idempotent consumers.",
      "sacrifices": "Introduces eventual consistency between MongoDB and PostgreSQL (sub-second lag at 200 writes/min, but not zero). Requires MongoDB replica set (Change Streams need oplog). Adds an operational component (CDC worker) to monitor.",
      "alternatives_considered": [
        "Application-level dual-write: Rejected — creates partial-failure scenarios where one write succeeds and the other fails, requiring complex compensation logic or distributed transactions",
        "Debezium CDC connector: Viable alternative, but adds Kafka dependency. MongoDB Change Streams are simpler for this scale."
      ]
    },
    {
      "decision": "Idempotent upserts (ON CONFLICT) for all PostgreSQL writes during migration",
      "gains": "Backfill and CDC can run concurrently without coordination. Out-of-order or duplicate events are harmless. Simplifies error recovery — just replay.",
      "sacrifices": "Slightly more expensive than plain INSERTs due to conflict detection. Requires a unique constraint on order_id (which we want anyway).",
      "alternatives_considered": [
        "Ordered processing with deduplication table: More complex, no meaningful benefit at this scale"
      ]
    },
    {
      "decision": "Shadow reads before cutover instead of direct switch",
      "gains": "Catches data transformation bugs, missing records, and query semantic differences under real production load before any user is affected.",
      "sacrifices": "Doubles read load during shadow phase. Adds ~5ms latency. Shadow phase may need to run 1-2 weeks for confidence.",
      "alternatives_considered": [
        "Skip shadow reads and rely on reconciliation only: Risky — reconciliation checks data equality but not query behavior"
      ]
    },
    {
      "decision": "PostgreSQL as target (vs other relational DBs)",
      "gains": "Strong ACID, excellent JSON support (jsonb) for gradual schema migration, rich ecosystem, cost-effective, supports complex reporting queries.",
      "sacrifices": "Team may need to learn PostgreSQL-specific tooling, connection pooling (pgbouncer), and vacuum tuning.",
      "alternatives_considered": [
        "MySQL: Viable but weaker JSON support and less flexible constraint system",
        "CockroachDB: Overkill for this scale, adds distributed DB complexity"
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Feature flag read/write source",
      "evolution_path": "Enables instant rollback at any phase. Can run shadow mode indefinitely if confidence is low. Supports percentage-based rollout to catch issues with small blast radius."
    },
    {
      "area": "Document-to-relational transform logic (shared library)",
      "evolution_path": "Transform logic is shared between CDC Worker and Backfill Job. As the MongoDB schema evolves during migration, only this library changes. Can be versioned independently."
    },
    {
      "area": "PostgreSQL schema can use jsonb columns for semi-structured fields",
      "evolution_path": "Not every MongoDB field needs to be a column on day one. Use jsonb for infrequently queried or volatile fields, then promote to proper columns as query patterns stabilize. Avoids premature normalization."
    },
    {
      "area": "CDC Worker is independently scalable",
      "evolution_path": "If write volume grows beyond 200/min, CDC Worker can be horizontally scaled by partitioning change streams by collection or shard key."
    }
  ],

  "rigidity_points": [
    {
      "area": "order_id must be consistent across both stores",
      "reason": "The entire migration hinges on a stable, unique order identifier that maps 1:1 between MongoDB _id and PostgreSQL order_id. Changing ID strategy mid-migration would be catastrophic."
    },
    {
      "area": "PostgreSQL schema must be finalized before backfill starts",
      "reason": "Schema changes during backfill require restarting the backfill or running ALTER TABLE migrations that may conflict with ongoing CDC writes. Get the schema right first."
    },
    {
      "area": "Migration phase ordering is strict",
      "reason": "Phases must proceed in order: Schema → CDC+Backfill → Verify → Shadow → Read Cutover → Write Cutover → Decommission. Skipping phases creates data loss risk."
    }
  ],

  "risks": [
    {
      "risk": "MongoDB document schema is inconsistent (schema drift over time) causing transform failures in CDC Worker",
      "severity": "high",
      "mitigation": "Before migration, run a schema analysis job across all 8M documents to catalog all field variations. Build transforms that handle every variant. Include a dead-letter queue in CDC Worker for documents that fail transformation — alert and fix without blocking the stream."
    },
    {
      "risk": "Backfill takes too long and CDC resume token expires (MongoDB oplog window overflow)",
      "severity": "critical",
      "mitigation": "Start CDC BEFORE backfill so the resume token is established. MongoDB oplog window must be sized to exceed backfill duration. At 8M docs with batch=1000 and throttling, estimate ~4-8 hours. Ensure oplog covers at least 72 hours. Monitor oplog window size."
    },
    {
      "risk": "Shadow reads reveal systematic divergence, blocking cutover indefinitely",
      "severity": "medium",
      "mitigation": "Define acceptable divergence thresholds (e.g., timestamp precision differences are acceptable, amount differences are not). Categorize divergences by severity. Fix transform bugs iteratively — each fix applies retroactively via re-backfill of affected records."
    },
    {
      "risk": "PostgreSQL connection exhaustion under dual read load during shadow phase",
      "severity": "high",
      "mitigation": "Deploy PgBouncer for connection pooling from day one. Shadow reads should use a separate connection pool with a hard limit. If pool is exhausted, skip shadow read (degrade gracefully) rather than failing the request."
    },
    {
      "risk": "Write cutover phase: brief window where writes go to both stores and one fails",
      "severity": "high",
      "mitigation": "Write cutover is atomic via feature flag: switch from 'mongo' to 'postgres' directly. Do NOT use a 'both' dual-write phase. The CDC pipeline ensures PostgreSQL is caught up. After read cutover is stable, flip write flag to 'postgres' and stop CDC. If a few last CDC events are lost, reconciliation catches them."
    },
    {
      "risk": "Team lacks PostgreSQL operational expertise (vacuum, connection management, query planning)",
      "severity": "medium",
      "mitigation": "Start PostgreSQL in staging 4+ weeks before production migration. Run load tests at 2x production volume. Document runbooks for vacuum, bloat, slow queries. Consider managed PostgreSQL (RDS/Cloud SQL) to reduce operational burden."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Execute in 5 phases over 6-8 weeks. Phase 1 (Week 1): Deploy PostgreSQL, create schema, deploy PgBouncer. Phase 2 (Week 2-3): Deploy CDC Worker, start consuming Change Streams, begin Backfill Job. Phase 3 (Week 3-4): Run Reconciliation until 100% match for 72h. Phase 4 (Week 4-6): Enable shadow reads at 1% → 10% → 100%. Fix divergences. Phase 5 (Week 6-8): Switch reads to PostgreSQL via flag. Monitor for 1 week. Switch writes to PostgreSQL. Decommission CDC and MongoDB.",
    "files_to_create_or_modify": [
      "db/postgres/migrations/001_create_orders_schema.sql — orders, order_items, payments, payment_events tables with FKs and indexes",
      "db/postgres/migrations/002_create_migration_tracking.sql — migration_sync_state, reconciliation_reports tables",
      "src/migration/transform.ts — Shared document-to-relational transform library (MongoDB doc → PG row mapping)",
      "src/migration/cdc-worker.ts — Change Stream consumer with resume token persistence and dead-letter queue",
      "src/migration/backfill-job.ts — Cursor-based bulk migration with throttling and progress tracking",
      "src/migration/reconciliation.ts — Sampling-based field-level comparison service",
      "src/orders/repository.ts — Modify to support feature-flag-driven read/write routing",
      "src/orders/shadow-read.ts — Shadow read middleware that compares MongoDB and PostgreSQL results",
      "config/feature-flags.ts — Migration-specific flags: order-read-source, order-write-target",
      "scripts/analyze-mongo-schema.ts — Pre-migration schema analysis across all 8M documents"
    ],
    "patterns_to_follow": "Repository pattern with strategy-based backend selection. The Order Repository interface stays stable — only the underlying implementation switches between MongoDB and PostgreSQL adapters. All migration components are behind the repository boundary, invisible to domain logic.",
    "pitfalls_to_avoid": [
      "DO NOT use application-level dual-writes — this creates distributed transaction problems that are nearly impossible to debug at scale",
      "DO NOT start backfill before CDC is running and has a resume token — you will miss writes that occur during backfill",
      "DO NOT assume MongoDB documents have consistent schemas — always handle missing fields, type variations, and nested structure differences",
      "DO NOT skip shadow reads — reconciliation checks data but not query behavior (e.g., sort order, null handling, type coercion differences)",
      "DO NOT run backfill against MongoDB primary — use secondaryPreferred read preference to avoid impacting production writes",
      "DO NOT attempt a big-bang cutover — the feature flag approach is essential for reversibility",
      "DO NOT delete MongoDB data until PostgreSQL has been primary for at least 30 days and you have verified backups"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 85,
    "high_confidence_areas": [
      "CDC via Change Streams is the correct pattern for this scale and zero-downtime requirement",
      "Strangler Fig with feature flags is the safest cutover strategy",
      "Idempotent upserts allow concurrent CDC + backfill without coordination",
      "PostgreSQL is the right target given the stated requirements (ACID, joins, FKs)"
    ],
    "low_confidence_areas": [
      "Exact MongoDB document schema variations — a schema analysis must be done before finalizing the PostgreSQL schema and transform logic",
      "Oplog window sizing — depends on MongoDB deployment configuration which was not provided",
      "Whether existing reporting queries can be directly translated to SQL or need redesign"
    ],
    "assumptions": [
      "MongoDB is running as a replica set (required for Change Streams)",
      "Order documents have a stable order_id field that can serve as the primary key in PostgreSQL",
      "The 200 writes/min figure is sustained average, not peak — peak may be 2-3x during promotions",
      "Team has access to deploy new services (CDC Worker) alongside existing infrastructure",
      "Feature flag infrastructure already exists or can be deployed quickly"
    ]
  }
}
